@ARTICLE{10.1111/jgh.70245,
	author = {Farah H and Kadhim-Abosaoda M and Mohaisen-Mousa H and Jyothi R and Priyadarshini-Nayak P and Janney-J B and Singh G and Singh-Chauhan A and Kumar-Mishra M},
	title = {Exosome-Based Strategies in Hepatocellular Carcinoma: Mechanisms, Immunotherapy, and Clinical Challenges.},
	journal = {J Gastroenterol Hepatol},
	year = {2026},
	abstract = {Hepatocellular carcinoma (HCC) remains one of the most prevalent and lethal malignancies worldwide, characterized by late diagnosis, limited therapeutic options, and poor prognosis. Conventional systemic therapies such as sorafenib and its successors provide only modest survival benefits and are frequently complicated by toxicity and drug resistance. In recent years, immunotherapy has emerged as a promising avenue, yet its efficacy is often restricted by the profoundly immunosuppressive tumor microenvironment (TME). Within this landscape, exosomes-nanoscale extracellular vesicles secreted by tumor, stromal, and immune cells-have gained increasing attention for their central role in intercellular communication. They influence immune modulation, metabolic reprogramming, and therapeutic resistance, while also serving as potential biomarkers, nanocarriers, and vaccine platforms. Tumor-derived exosomes (TEXs) contribute to immune evasion by suppressing CD8+ T cells, polarizing macrophages toward protumoral phenotypes, and enhancing immune checkpoint resistance. Conversely, engineered exosomes demonstrate significant therapeutic potential by reprogramming TAMs, improving drug delivery, and acting as cancer vaccines. Despite these advances, challenges remain in exosome biogenesis, heterogeneity, large-scale production, and off-target effects, which hinder clinical translation. Furthermore, interactions between exosomes and gut microbiota in modulating hepatic immunity represent an emerging frontier with unexplored therapeutic implications. Continued advances in bioengineering, nanotechnology, and systems biology are expected to refine exosome-based therapies, offering novel, personalized strategies to improve outcomes for HCC patients.},
	doi = {10.1111/jgh.70245},
	pmid = {41623268 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1754107,
	author = {Kang R and Sun A and Yang J and Chang L and Sun W and Kou F and Cheng Y},
	title = {Targeting the plasticity of intestinal neutrophils: bidirectional regulation strategies by natural products.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {Historically, neutrophils have been regarded primarily as pro-inflammatory cells, yet recent advancements have revealed their phenotypic heterogeneity and functional plasticity with versatile immunophenotypes. Distinct subpopulations of neutrophils exhibit a functional duality, not only initiating and amplifying inflammation, but also actively promoting tissue restoration in diseases, such as inflammatory bowel disease (IBD), colorectal cancer (CRC) and intestinal infections. They contribute to the formation of a dynamic immune microenvironment in concert with the intestinal microbiota, epithelial cells, and other immune cell types. Current first-line therapies for enteric diseases often lack precision in modulating neutrophil functions. In contrast, natural products including alkaloids, polysaccharides, polyphenols, quinones, and glycosides, as well as microbiota-derived metabolites, exhibit distinct advantages for ability to achieve multi-targeted and bidirectional immunomodulation. These compounds target neutrophil activation, migration, neutrophil extracellular trap formation, cytokine release, oxidative stress, and energy metabolism etc. In this review, we systematically examine the heterogeneity and functional diversity of intestinal neutrophils, highlighting their interaction mechanisms with the surrounding microenvironment. Potential of natural products to modulate neutrophil functions via multi-target strategies has not been fully explored. Moreover, the review discusses novel precision therapeutic approaches based on neutrophil nanotechnology and engineered cell drug delivery. These cutting-edge technologies aim to enhance natural products delivery to inflammatory sites, provide controllable regulation of neutrophil function, and facilitate the degradation of pathological structures. Collectively, the study presents new research directions and theoretical frameworks for intervention of natural products in neutrophils of intestinal immune-related disorders, notably IBD and even CRC.},
	doi = {10.3389/fimmu.2025.1754107},
	pmid = {41601690 [Indexed for MEDLINE]},
	note = {PMC12833395}
}
